docling_figure_rich('docs/research_assets/research/student_work_figures/2026-06-18-docling-figures/MERJ_Ramful_2014_Proportional/p17_1.png', 'MERJ_Ramful_2014_Proportional', 'preservice teachers', false, core{representation_language: none, spatial_elements: [], transcribed_math: 'I2O5 + 5CO -> 5CO2 + I2; 2Na2S2O3 + I2 -> Na2S4O6 + 2NaI; 2 moles Na2S2O3 -> 5 moles CO; 1 mole Na2S2O3 -> 5/2 mol CO; Mr CO = 12+6 = 18; 5/2 * 18 = 45g', description: 'The student is using stoichiometry to calculate the mass of CO produced based on chemical equations and molar mass.'}, coding{domains: [proportional], error_topics: ['stoichiometry / Molar vs non-molar quantities'], strategy_topics: []}, none, 'The student is using stoichiometry to calculate the mass of CO produced based on chemical equations and molar mass.').
